# ---------------------------------------------------------------------------
# Shared Boto3 Client Factory (connection reuse across invocations)
# ---------------------------------------------------------------------------
class AWSClientFactory:
    """Creates and caches boto3 clients for reuse across Lambda invocations."""

    _clients: Dict[str, Any] = {}
    _boto_config = Config(
        retries={"max_attempts": 3, "mode": "adaptive"},
        connect_timeout=5,
        read_timeout=10,
    )

    @classmethod
    def get_client(cls, service_name: str):
        if service_name not in cls._clients:
            cls._clients[service_name] = boto3.client(
                service_name,
                region_name=config.AWS_REGION,
                config=cls._boto_config,
            )
        return cls._clients[service_name]

    @classmethod
    def get_resource(cls, service_name: str):
        key = f"{service_name}_resource"
        if key not in cls._clients:
            cls._clients[key] = boto3.resource(
                service_name,
                region_name=config.AWS_REGION,
                config=cls._boto_config,
            )
        return cls._clients[key]


# ---------------------------------------------------------------------------
# Shared Service Helpers — reusable across all 10+ Lambda functions
# ---------------------------------------------------------------------------
class DynamoDBService:
    """Common DynamoDB operations."""

    def __init__(self, table_name: Optional[str] = None):
        self.table_name = table_name or config.DYNAMODB_TABLE
        self._resource = AWSClientFactory.get_resource("dynamodb")
        self._table = self._resource.Table(self.table_name)

    def get_item(self, key: Dict) -> Optional[Dict]:
        try:
            resp = self._table.get_item(Key=key)
            return resp.get("Item")
        except ClientError as exc:
            logger.error("DynamoDB get_item error: %s", exc)
            raise

    def put_item(self, item: Dict) -> Dict:
        try:
            item["updated_at"] = datetime.now(timezone.utc).isoformat()
            return self._table.put_item(Item=item)
        except ClientError as exc:
            logger.error("DynamoDB put_item error: %s", exc)
            raise

    def update_item(self, key: Dict, update_expression: str,
                    expression_values: Dict,
                    expression_names: Optional[Dict] = None) -> Dict:
        try:
            kwargs = {
                "Key": key,
                "UpdateExpression": update_expression,
                "ExpressionAttributeValues": expression_values,
                "ReturnValues": "ALL_NEW",
            }
            if expression_names:
                kwargs["ExpressionAttributeNames"] = expression_names
            return self._table.update_item(**kwargs)
        except ClientError as exc:
            logger.error("DynamoDB update_item error: %s", exc)
            raise

    def query_items(self, key_condition, index_name: Optional[str] = None,
                    limit: int = 100) -> list:
        try:
            kwargs = {"KeyConditionExpression": key_condition, "Limit": limit}
            if index_name:
                kwargs["IndexName"] = index_name
            resp = self._table.query(**kwargs)
            return resp.get("Items", [])
        except ClientError as exc:
            logger.error("DynamoDB query error: %s", exc)
            raise

    def delete_item(self, key: Dict) -> Dict:
        try:
            return self._table.delete_item(Key=key)
        except ClientError as exc:
            logger.error("DynamoDB delete_item error: %s", exc)
            raise


class S3Service:
    """Common S3 operations."""

    def __init__(self, bucket_name: Optional[str] = None):
        self.bucket = bucket_name or config.S3_BUCKET
        self.client = AWSClientFactory.get_client("s3")

    def get_object(self, key: str) -> bytes:
        try:
            resp = self.client.get_object(Bucket=self.bucket, Key=key)
            return resp["Body"].read()
        except ClientError as exc:
            logger.error("S3 get_object error for key %s: %s", key, exc)
            raise

    def put_object(self, key: str, body: bytes, content_type: str = "application/json",
                   metadata: Optional[Dict] = None) -> Dict:
        try:
            kwargs = {
                "Bucket": self.bucket,
                "Key": key,
                "Body": body,
                "ContentType": content_type,
            }
            if metadata:
                kwargs["Metadata"] = metadata
            return self.client.put_object(**kwargs)
        except ClientError as exc:
            logger.error("S3 put_object error for key %s: %s", key, exc)
            raise

    def delete_object(self, key: str) -> Dict:
        try:
            return self.client.delete_object(Bucket=self.bucket, Key=key)
        except ClientError as exc:
            logger.error("S3 delete_object error for key %s: %s", key, exc)
            raise

    def generate_presigned_url(self, key: str, expiration: int = 3600) -> str:
        try:
            return self.client.generate_presigned_url(
                "get_object",
                Params={"Bucket": self.bucket, "Key": key},
                ExpiresIn=expiration,
            )
        except ClientError as exc:
            logger.error("S3 presigned URL error for key %s: %s", key, exc)
            raise


class SNSService:
    """Common SNS operations."""

    def __init__(self, topic_arn: Optional[str] = None):
        self.topic_arn = topic_arn or config.SNS_TOPIC_ARN
        self.client = AWSClientFactory.get_client("sns")

    def publish(self, message: Dict, subject: Optional[str] = None,
                message_attributes: Optional[Dict] = None) -> Dict:
        if not config.ENABLE_NOTIFICATIONS:
            logger.info("Notifications disabled; skipping SNS publish")
            return {"MessageId": "notifications-disabled"}
        try:
            kwargs = {
                "TopicArn": self.topic_arn,
                "Message": json.dumps(message, default=str),
            }
            if subject:
                kwargs["Subject"] = subject
            if message_attributes:
                kwargs["MessageAttributes"] = message_attributes
            resp = self.client.publish(**kwargs)
            logger.info("Published to SNS topic %s, MessageId=%s",
                        self.topic_arn, resp["MessageId"])
            return resp
        except ClientError as exc:
            logger.error("SNS publish error: %s", exc)
            raise


class SQSService:
    """Common SQS operations."""

    def __init__(self, queue_url: Optional[str] = None):
        self.queue_url = queue_url or config.SQS_QUEUE_URL
        self.client = AWSClientFactory.get_client("sqs")

    def send_message(self, message_body: Dict, delay_seconds: int = 0,
                     message_attributes: Optional[Dict] = None,
                     message_group_id: Optional[str] = None) -> Dict:
        try:
            kwargs = {
                "QueueUrl": self.queue_url,
                "MessageBody": json.dumps(message_body, default=str),
                "DelaySeconds": delay_seconds,
            }
            if message_attributes:
                kwargs["MessageAttributes"] = message_attributes
            if message_group_id:
                kwargs["MessageGroupId"] = message_group_id
            resp = self.client.send_message(**kwargs)
            logger.info("Sent SQS message %s to %s",
                        resp["MessageId"], self.queue_url)
            return resp
        except ClientError as exc:
            logger.error("SQS send_message error: %s", exc)
            raise

    def send_message_batch(self, entries: list) -> Dict:
        try:
            return self.client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=entries,
            )
        except ClientError as exc:
            logger.error("SQS send_message_batch error: %s", exc)
            raise

    def delete_message(self, receipt_handle: str) -> Dict:
        try:
            return self.client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
            )
        except ClientError as exc:
            logger.error("SQS delete_message error: %s", exc)
            raise


class CloudWatchMetrics:
    """Custom CloudWatch metrics helper."""

    def __init__(self):
        self.client = AWSClientFactory.get_client("cloudwatch")
        self.namespace = f"{config.PROJECT_NAME}/{config.ENVIRONMENT}"

    def put_metric(self, metric_name: str, value: float, unit: str = "Count",
                   dimensions: Optional[list] = None):
        try:
            metric_data = {
                "MetricName": metric_name,
                "Value": value,
                "Unit": unit,
                "Timestamp": datetime.now(timezone.utc),
            }
            if dimensions:
                metric_data["Dimensions"] = dimensions
            self.client.put_metric_data(
                Namespace=self.namespace,
                MetricData=[metric_data],
            )
        except ClientError as exc:
            logger.warning("CloudWatch put_metric error (non-fatal): %s", exc)


# ---------------------------------------------------------------------------
# Decorator: standard Lambda response handling, logging, and error trapping
# ---------------------------------------------------------------------------
def lambda_response_handler(func):
    """Decorator that wraps a Lambda handler with structured logging,
    timing, error handling, and a consistent API Gateway response format."""

    @wraps(func)
    def wrapper(event, context):
        request_id = getattr(context, "aws_request_id", "unknown")
        function_name = getattr(context, "function_name", "unknown")
        start = time.time()

        logger.info(
            "START request_id=%s function=%s event_source=%s",
            request_id,
            function_name,
            _detect_event_source(event),
        )

        try:
            result = func(event, context)
            duration_ms = (time.time() - start) * 1000
            logger.info(
                "END request_id=%s duration=%.2fms status=success",
                request_id, duration_ms,
            )

            # If the handler already returned a properly formatted response
            if isinstance(result, dict) and "statusCode" in result:
                return result

            return _build_response(200, result)

        except ValidationError as exc:
            duration_ms = (time.time() - start) * 1000
            logger.warning(
                "VALIDATION_ERROR request_id=%s duration=%.2fms error=%s",
                request_id, duration_ms, str(exc),
            )
            return _build_response(400, {"error": str(exc), "type": "ValidationError"})

        except ResourceNotFoundError as exc:
            duration_ms = (time.time() - start) * 1000
            logger.warning(
                "NOT_FOUND request_id=%s duration=%.2fms error=%s",
                request_id, duration_ms, str(exc),
            )
            return _build_response(404, {"error": str(exc), "type": "NotFound"})

        except Exception as exc:
            duration_ms = (time.time() - start) * 1000
            logger.error(
                "UNHANDLED_ERROR request_id=%s duration=%.2fms error=%s\n%s",
                request_id, duration_ms, str(exc), traceback.format_exc(),
            )
            return _build_response(500, {
                "error": "Internal server error",
                "request_id": request_id,
            })

    return wrapper


# ---------------------------------------------------------------------------
# Custom Exceptions
# ---------------------------------------------------------------------------
class ValidationError(Exception):
    """Raised when request validation fails."""
    pass


class ResourceNotFoundError(Exception):
    """Raised when a requested resource does not exist."""
    pass


# ---------------------------------------------------------------------------
# Utility helpers
# ---------------------------------------------------------------------------
def _detect_event_source(event: Dict) -> str:
    """Best-effort detection of the event source for logging."""
    if "Records" in event:
        first = event["Records"][0]
        if "eventSource" in first:
            return first["eventSource"]
        if "EventSource" in first:
            return first["EventSource"]
    if "httpMethod" in event or "requestContext" in event:
        return "api-gateway"
    if "detail-type" in event:
        return "eventbridge"
    if "source" in event:
        return event["source"]
    return "unknown"


def _build_response(status_code: int, body: Any) -> Dict:
    """Build a standard API Gateway proxy response."""
    return {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json",
            "X-Request-Time": datetime.now(timezone.utc).isoformat(),
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
            "Access-Control-Allow-Headers": "Content-Type,Authorization",
        },
        "body": json.dumps(body, default=str),
    }


def parse_api_gateway_body(event: Dict) -> Dict:
    """Parse and return the JSON body from an API Gateway event."""
    body = event.get("body")
    if body is None:
        raise ValidationError("Request body is required")
    if isinstance(body, str):
        try:
            return json.loads(body)
        except json.JSONDecodeError as exc:
            raise ValidationError(f"Invalid JSON in request body: {exc}")
    return body


def get_path_parameter(event: Dict, name: str) -> str:
    """Retrieve a required path parameter."""
    params = event.get("pathParameters") or {}
    value = params.get(name)
    if not value:
        raise ValidationError(f"Missing required path parameter: {name}")
    return value


def get_query_parameter(event: Dict, name: str,
                        default: Optional[str] = None) -> Optional[str]:
    """Retrieve an optional query-string parameter."""
    params = event.get("queryStringParameters") or {}
    return params.get(name, default)


# ---------------------------------------------------------------------------
# Example Lambda Handler — Order Processing Microservice
# ---------------------------------------------------------------------------
# In a real deployment each Lambda function lives in its own file/package
# but they ALL share the same IAM role ARN defined above.
# ---------------------------------------------------------------------------

# Initialise service helpers outside the handler for connection reuse
dynamo = DynamoDBService()
s3 = S3Service()
sns = SNSService()
sqs = SQSService()
metrics = CloudWatchMetrics()


@lambda_response_handler
def lambda_handler(event: Dict, context) -> Dict:
    """
    Example: Order Processing Lambda.

    Supports:
        POST   /orders          — Create a new order
        GET    /orders/{id}     — Get order by ID
        PUT    /orders/{id}     — Update order status
        DELETE /orders/{id}     — Cancel order

    All 10+ Lambda functions in the architecture use the SAME shared IAM role
    (SharedLambdaExecutionRole) so they can access S3, DynamoDB, SNS, and SQS
    without per-function IAM role definitions.
    """
    http_method = event.get("httpMethod", "")
    resource = event.get("resource", "")

    logger.info("Processing %s %s", http_method, resource)

    # ---- Route: POST /orders ----
    if http_method == "POST" and resource == "/orders":
        return _create_order(event)

    # ---- Route: GET /orders/{id} ----
    if http_method == "GET" and resource == "/orders/{id}":
        return _get_order(event)

    # ---- Route: PUT /orders/{id} ----
    if http_method == "PUT" and resource == "/orders/{id}":
        return _update_order(event)

    # ---- Route: DELETE /orders/{id} ----
    if http_method == "DELETE" and resource == "/orders/{id}":
        return _cancel_order(event)

    # ---- SQS Event Processing ----
    if "Records" in event:
        return _process_sqs_records(event)

    raise ValidationError(f"Unsupported route: {http_method} {resource}")


# ---------------------------------------------------------------------------
# Route Implementations
# ---------------------------------------------------------------------------

def _create_order(event: Dict) -> Dict:
    """Create a new order — uses DynamoDB, S3, SNS, SQS."""
    body = parse_api_gateway_body(event)

    # Validate required fields
    required = ["customer_id", "items", "total_amount"]
    missing = [f for f in required if f not in body]
    if missing:
        raise ValidationError(f"Missing required fields: {', '.join(missing)}")

    order_id = f"ORD-{int(datetime.now(timezone.utc).timestamp() * 1000)}"
    now = datetime.now(timezone.utc).isoformat()

    order = {
        "order_id": order_id,
        "customer_id": body["customer_id"],
        "items": body["items"],
        "total_amount": str(body["total_amount"]),
        "status": "PENDING",
        "created_at": now,
        "updated_at": now,
    }

    # 1. Store in DynamoDB
    dynamo.put_item(order)
    logger.info("Order %s stored in DynamoDB", order_id)

    # 2. Store order details JSON in S3 for archival
    s3.put_object(
        key=f"orders/{order_id}/details.json",
        body=json.dumps(order, default=str).encode("utf-8"),
        metadata={"customer_id": body["customer_id"]},
    )
    logger.info("Order %s archived to S3", order_id)

    # 3. Publish event to SNS for other microservices
    sns.publish(
        message={
            "event_type": "ORDER_CREATED",
            "order_id": order_id,
            "customer_id": body["customer_id"],
            "total_amount": str(body["total_amount"]),
            "timestamp": now,
        },
        subject="Order Created",
        message_attributes={
            "event_type": {
                "DataType": "String",
                "StringValue": "ORDER_CREATED",
            },
        },
    )

    # 4. Queue fulfilment task via SQS
    sqs.send_message(
        message_body={
            "action": "PROCESS_ORDER",
            "order_id": order_id,
            "customer_id": body["customer_id"],
            "items": body["items"],
            "timestamp": now,
        },
        delay_seconds=0,
    )

    # 5. Emit custom metric
    metrics.put_metric(
        "OrdersCreated", 1, "Count",
        dimensions=[{"Name": "Service", "Value": "OrderProcessor"}],
    )

    return {"message": "Order created successfully", "order_id": order_id, "order": order}


def _get_order(event: Dict) -> Dict:
    """Retrieve an order by ID from DynamoDB."""
    order_id = get_path_parameter(event, "id")
    order = dynamo.get_item({"order_id": order_id})
    if not order:
        raise ResourceNotFoundError(f"Order {order_id} not found")
    return {"order": order}


def _update_order(event: Dict) -> Dict:
    """Update order status."""
    order_id = get_path_parameter(event, "id")
    body = parse_api_gateway_body(event)

    new_status = body.get("status")
    valid_statuses = {"PENDING", "PROCESSING", "SHIPPED", "DELIVERED", "CANCELLED"}
    if new_status not in valid_statuses:
        raise ValidationError(
            f"Invalid status '{new_status}'. Must be one of: {', '.join(sorted(valid_statuses))}"
        )

    # Ensure the order exists
    existing = dynamo.get_item({"order_id": order_id})
    if not existing:
        raise ResourceNotFoundError(f"Order {order_id} not found")

    resp = dynamo.update_item(
        key={"order_id": order_id},
        update_expression="SET #s = :status, updated_at = :ts",
        expression_names={"#s": "status"},
        expression_values={
            ":status": new_status,
            ":ts": datetime.now(timezone.utc).isoformat(),
        },
    )

    # Notify downstream services
    sns.publish(
        message={
            "event_type": "ORDER_STATUS_CHANGED",
            "order_id": order_id,
            "old_status": existing.get("status"),
            "new_status": new_status,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        },
        subject="Order Status Changed",
    )

    return {"message": f"Order {order_id} updated to {new_status}",
            "order": resp.get("Attributes", {})}


def _cancel_order(event: Dict) -> Dict:
    """Cancel an order."""
    order_id = get_path_parameter(event, "id")
    existing = dynamo.get_item({"order_id": order_id})
    if not existing:
        raise ResourceNotFoundError(f"Order {order_id} not found")

    if existing.get("status") in {"SHIPPED", "DELIVERED"}:
        raise ValidationError(
            f"Cannot cancel order in '{existing['status']}' status"
        )

    dynamo.update_item(
        key={"order_id": order_id},
        update_expression="SET #s = :status, updated_at = :ts",
        expression_names={"#s": "status"},
        expression_values={
            ":status": "CANCELLED",
            ":ts": datetime.now(timezone.utc).isoformat(),
        },
    )

    sns.publish(
        message={
            "event_type": "ORDER_CANCELLED",
            "order_id": order_id,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        },
        subject="Order Cancelled",
    )

    metrics.put_metric(
        "OrdersCancelled", 1, "Count",
        dimensions=[{"Name": "Service", "Value": "OrderProcessor"}],
    )

    return {"message": f"Order {order_id} cancelled successfully"}


def _process_sqs_records(event: Dict) -> Dict:
    """Process incoming SQS messages (e.g. from the fulfilment queue)."""
    processed = 0
    failed = 0

    for record in event.get("Records", []):
        try:
            body = json.loads(record["body"])
            action = body.get("action")
            order_id = body.get("order_id")

            logger.info("Processing SQS message: action=%s order_id=%s",
                        action, order_id)

            if action == "PROCESS_ORDER":
                dynamo.update_item(
                    key={"order_id": order_id},
                    update_expression="SET #s = :status, updated_at = :ts",
                    expression_names={"#s": "status"},
                    expression_values={
                        ":status": "PROCESSING",
                        ":ts": datetime.now(timezone.utc).isoformat(),
                    },
                )
                logger.info("Order %s moved to PROCESSING", order_id)
            else:
                logger.warning("Unknown action '%s' for order %s", action, order_id)

            processed += 1

        except Exception as exc:
            failed += 1
            logger.error("Failed to process SQS record: %s\n%s",
                         str(exc), traceback.format_exc())

            # Send to DLQ for manual inspection
            if config.SQS_DLQ_URL:
                dlq = SQSService(queue_url=config.SQS_DLQ_URL)
                dlq.send_message({
                    "original_record": record,
                    "error": str(exc),
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                })

    metrics.put_metric(
        "SQSMessagesProcessed", processed, "Count",
        dimensions=[{"Name": "Service", "Value": "OrderProcessor"}],
    )
    if failed:
        metrics.put_metric(
            "SQSMessagesFailed", failed, "Count",
            dimensions=[{"Name": "Service", "Value": "OrderProcessor"}],
        )

    return {"processed": processed, "failed": failed}


